package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetQuoteChar_withNonNullQuoteChar() {
        // Using DEFAULT which has DOUBLE_QUOTE_CHAR as quoteChar
        CSVFormat format = CSVFormat.DEFAULT;
        Character quoteChar = format.getQuoteChar();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());
    }

    @Test
    public void testGetQuoteChar_withNullQuoteChar() {
        // Create CSVFormat with null quoteChar using withQuoteChar(Character)
        CSVFormat format = CSVFormat.DEFAULT.withQuoteChar((Character) null);
        Character quoteChar = format.getQuoteChar();
        assertNull(quoteChar);
    }

    @Test
    public void testGetQuoteChar_withCustomQuoteChar() {
        // Create CSVFormat with custom quoteChar using withQuoteChar(char)
        CSVFormat format = CSVFormat.DEFAULT.withQuoteChar('\'');
        Character quoteChar = format.getQuoteChar();
        assertNotNull(quoteChar);
        assertEquals('\'', quoteChar.charValue());
    }
}
